    printerFingerprint ||
    hasAny(text, printerHints) ||
    printerVendor ||
    hasPort(portSet, [9100, 515, 631, 9101, 9102]) ||
    hasAny(services, ['jetdirect', 'ipp', 'lpd', 'printer'])
  ) {
