app.post('/export-xlsx', async (req, res) => {
  const results = Array.isArray(req.body.results) ? req.body.results : [];

  const workbook = new ExcelJS.Workbook();
  workbook.creator = 'NetScan Canon';
  workbook.created = new Date();

  const worksheet = workbook.addWorksheet('NetScan Canon', {
    views: [{ state: 'frozen', ySplit: 2 }],
    properties: { defaultRowHeight: 18 }
  });

  const headers = [
    { header: 'IP', key: 'ip', width: 16 },
    { header: 'Estado', key: 'status', width: 12 },
    { header: 'Hostname', key: 'hostname', width: 28 },
    { header: 'MAC', key: 'mac', width: 18 },
    { header: 'Fabricante', key: 'vendor', width: 22 },
    { header: 'Sistema Operacional', key: 'os', width: 28 },
    { header: 'Versão OS', key: 'osVersion', width: 16 },
    { header: 'VM', key: 'vm', width: 10 },
    { header: 'Tipo VM', key: 'vmType', width: 14 },
    { header: 'Confiança VM', key: 'vmConfidence', width: 12 },
    { header: 'Domínio AD', key: 'adDomain', width: 18 },
    { header: 'Descrição AD', key: 'description', width: 26 },
    { header: 'DN AD', key: 'adDn', width: 36 },
    { header: 'LastLogon AD', key: 'lastLogon', width: 20 },
    { header: 'VLAN', key: 'vlan', width: 22 },
    { header: 'VLAN ID', key: 'vlanId', width: 10 },
    { header: 'Fonte VLAN', key: 'vlanSource', width: 26 },
    { header: 'Sub-rede', key: 'subnet', width: 16 },
    { header: 'DMZ', key: 'dmz', width: 8 },
    { header: 'Ambiente', key: 'environment', width: 12 },
    { header: 'Tipo', key: 'deviceType', width: 22 },
    { header: 'Fontes', key: 'sources', width: 24 },
    { header: 'Portas Abertas', key: 'ports', width: 42 }
  ];

  worksheet.columns = headers.map(h => ({ key: h.key, width: h.width }));

  // Title band
  worksheet.mergeCells(1, 1, 1, headers.length);
  const titleCell = worksheet.getCell(1, 1);
  titleCell.value = `NetScan Canon — Varredura de Rede · ${new Date().toLocaleString('pt-BR')}`;
  titleCell.font = { bold: true, size: 14, color: { argb: 'FFF8FAFC' } };
  titleCell.fill = {
    type: 'pattern',
    pattern: 'solid',
    fgColor: { argb: 'FF0B1220' }
  };
  titleCell.alignment = { vertical: 'middle', horizontal: 'left', indent: 1 };
  worksheet.getRow(1).height = 28;

  // Header row
  const headerRow = worksheet.getRow(2);
  headers.forEach((h, i) => {
    const cell = headerRow.getCell(i + 1);
    cell.value = h.header;
    cell.font = { bold: true, color: { argb: 'FFFFFFFF' }, size: 10 };
    cell.fill = {
      type: 'pattern',
      pattern: 'solid',
      fgColor: { argb: 'FF0E7490' }
    };
    cell.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };
    cell.border = {
      bottom: { style: 'thin', color: { argb: 'FF067A8A' } }
    };
  });
  headerRow.height = 24;

  worksheet.autoFilter = {
    from: { row: 2, column: 1 },
    to: { row: 2, column: headers.length }
  };

  results.forEach((host, index) => {
    const ports = Array.isArray(host.ports) ? host.ports.filter(p => p && p.state === 'open') : [];
    const portsStr = ports.length > 0
      ? ports.map(p => `${p.port}/${p.protocol || 'TCP'}${p.service ? ` (${p.service})` : ''}`).join(', ')
      : 'Nenhuma';

    const row = worksheet.addRow({
      ip: host.ip,
      status: host.status,
      hostname: host.hostname,
      mac: host.mac,
      vendor: host.vendor,
      os: host.os,
      osVersion: host.osVersion || 'N/A',
      vm: host.vm || 'Não',
      vmType: host.vmType || 'N/A',
      vmConfidence: host.vmConfidence || 'N/A',
      adDomain: host.adDomain || 'N/A',
      description: host.description || 'N/A',
      adDn: host.adDn || 'N/A',
      lastLogon: host.lastLogon || 'N/A',
      vlan: host.vlan || 'N/A',
      vlanId: host.vlanId != null ? host.vlanId : 'N/A',
      vlanSource: host.vlanSource || 'N/A',
      subnet: host.subnet || 'N/A',
      dmz: host.isDMZ ? 'Sim' : 'Não',
      environment: host.environment || 'IT',
      deviceType: host.deviceType || 'Host Ativo',
      sources: Array.isArray(host.enrichmentSources) ? host.enrichmentSources.join(', ') : '',
      ports: portsStr
    });

    row.alignment = { vertical: 'middle', wrapText: true };
    row.eachCell((cell) => {
      cell.border = {
        top: { style: 'hair', color: { argb: 'FFE2E8F0' } },
        bottom: { style: 'hair', color: { argb: 'FFE2E8F0' } }
      };
    });

    if (index % 2 === 0) {
      row.eachCell((cell) => {
        cell.fill = {
          type: 'pattern',
          pattern: 'solid',
          fgColor: { argb: 'FFF0FDFA' }
        };
      });
    }

    const statusCell = row.getCell('status');
    if (host.status === 'Ativo') {
      statusCell.font = { bold: true, color: { argb: 'FF047857' } };
    } else {
      statusCell.font = { color: { argb: 'FFB91C1C' } };
    }

    const vmCell = row.getCell('vm');
    if (host.vm === 'Sim') {
      vmCell.font = { bold: true, color: { argb: 'FFC2410C' } };
    }
  });

  try {
    const buffer = await workbook.xlsx.writeBuffer();
    const now = new Date();
    const dateStr = now.toISOString().slice(0, 10);
    const timeStr = now.toTimeString().slice(0, 8).replace(/:/g, '-');
    const fileName = `NetScan_Canon_scan_${dateStr}_${timeStr}.xlsx`;

    // Um único arquivo: só o download HTTP (sem cópia extra em Documents)
    res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
    res.setHeader('Content-Disposition', `attachment; filename="${fileName}"`);
    res.send(Buffer.from(buffer));
  } catch (error) {
    console.error('Erro exportando XLSX:', error);
    res.status(500).json({ error: 'Falha ao gerar o arquivo Excel.' });
  }
});

