function broadcastLoopMsg(payload) {
  const raw = JSON.stringify(payload);
  wss.clients.forEach((client) => {
    if (client.readyState === WebSocket.OPEN) {
      try { client.send(raw); } catch { /* ignore */ }
    }
  });
}

