    (vendor.includes('hp') && (vendor.includes('printer') || text.includes('laser') || text.includes('jet'))) ||
    hasAny(vendor, ['canon', 'epson', 'brother', 'lexmark', 'xerox', 'kyocera', 'ricoh', 'konica', 'minolta'])
  );
  const printerFingerprint =
    !!(host.deviceHints && host.deviceHints.printer) ||
    (Array.isArray(host.printerEvidence) && host.printerEvidence.length > 0) ||
    (Array.isArray(host.openPrintPorts) && host.openPrintPorts.length > 0);

  if (
    printerFingerprint ||
