      'beckman', 'roche lab', 'abbott lab', 'gasometria', 'hemogasometria',
      'blood gas', 'urinalise', 'urinálise', 'microbiologia'
    ]) ||
    hasAny(vendor, ['sysmex', 'beckman', 'roche', 'abbott diagnostics'])
  ) {
    return 'Laboratório / Analisador';
  }

