  if (nodes.length === 0) {
    container.innerHTML = '<div class="terminal-line error-msg">Nenhum resultado de varredura disponível para gerar o mapa.</div>';
    return;
  }

  const data = {
    nodes: new vis.DataSet(nodes),
    edges: new vis.DataSet(edges)
  };

  const options = {
    nodes: {
      shape: 'dot',
      size: 18,
      font: { color: '#ffffff', size: 12, face: 'Plus Jakarta Sans' }
    },
    edges: {
      color: { color: '#8e96b5', highlight: '#f59e0b' },
      width: 2,
      smooth: { type: 'cubicBezier' }
    },
    layout: {
      improvedLayout: true
    },
    physics: {
      enabled: true,
      stabilization: {
        enabled: true,
        iterations: 300,
        updateInterval: 50
      },
      barnesHut: {
        gravitationalConstant: -2000,
        centralGravity: 0.18,
        springLength: 180,
        springConstant: 0.04,
        damping: 0.09
      }
    },
    interaction: {
      hover: true,
      tooltipDelay: 100,
      dragView: true,
      zoomView: true,
      multiselect: false
    }
  };

  networkInstance = new vis.Network(container, data, options);
  networkInstance.once('stabilizationIterationsDone', () => {
    networkInstance.fit({ animation: true, easingFunction: 'easeInOutQuad', duration: 600 });
  });
  networkInstance.on('resize', () => networkInstance.fit({ animation: { duration: 400, easingFunction: 'easeInOutQuad' } }));

  networkInstance.on('click', (params) => {
    if (params.nodes && params.nodes.length > 0) {
      const nodeId = params.nodes[0];
      const node = nodes.find(n => n.id === nodeId);
      if (node && node.data && node.data.ip) {
        // Scroll table to host row
        const row = document.getElementById(`row-${node.data.ip.replace(/\./g, '_')}`);
        if (row) {
          row.scrollIntoView({ behavior: 'smooth', block: 'center' });
          row.classList.add('highlight-row');
          setTimeout(() => row.classList.remove('highlight-row'), 2500);
        }
      }
    }
  });
}

function buildTopologyFromResults(results) {
  const nodes = [];
  const edges = [];

  // Map VLAN/subnet groups to colors
  const vlanMap = {};
  const vlanColors = ['#4facfe','#00f2fe','#10b981','#f59e0b','#ef4444','#8b5cf6','#fb7185'];
  let vlanIdx = 0;

  // Create subnet nodes
  const subnets = {};
  results.forEach(h => {
    const subnet = h.subnet || 'unknown';
    if (!subnets[subnet]) subnets[subnet] = { id: `subnet:${subnet}`, hosts: [] };
    subnets[subnet].hosts.push(h);
  });

  Object.keys(subnets).forEach((subnet, idx) => {
    nodes.push({ id: `subnet:${subnet}`, label: subnet, shape: 'box', color: '#222', font: { color: '#fff' }, data: { subnet } });
  });

  // Host nodes
  results.forEach(host => {
    const id = `host:${host.ip}`;
    const label = `${host.ip}\n${host.hostname !== 'N/A' ? host.hostname : ''}`;
    const vlan = host.vlan || 'default';
    if (!vlanMap[vlan]) vlanMap[vlan] = vlanColors[vlanIdx++ % vlanColors.length];

    const color = host.environment === 'OT/ICS' ? '#ff8a65' : (host.isDMZ ? '#f59e0b' : vlanMap[vlan]);

    nodes.push({ id, label, title: `${host.ip}\n${host.vendor}\n${host.os}`, group: vlan, color: { background: color }, data: { ip: host.ip, host } });

    // Edge to subnet
    const subnetId = `subnet:${host.subnet || 'unknown'}`;
    edges.push({ from: id, to: subnetId });
  });

  return { nodes, edges };
}

// --- Idle hosts analysis ---
let lastIdlePayload = null;

function escapeHtml(value) {
  return String(value == null ? '' : value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function formatLocalDateTime(isoOrMs) {
  if (isoOrMs == null || isoOrMs === '') return '—';
  const d = typeof isoOrMs === 'number' ? new Date(isoOrMs) : new Date(isoOrMs);
  if (Number.isNaN(d.getTime())) return '—';
  return d.toLocaleString('pt-BR');
}

function buildIdleQueryParams() {
  const raw = parseInt(document.getElementById('idle-value').value, 10);
  const value = Number.isFinite(raw) && raw >= 0 ? raw : 0;
  const unit = document.getElementById('idle-unit').value;
  const params = new URLSearchParams();
  if (unit === 'minutes') params.set('minutes', String(value));
  else if (unit === 'hours') params.set('hours', String(value));
  else params.set('days', String(value));
  return params;
}

function setIdleStatus(message, isError = false) {
  const el = document.getElementById('idle-status');
  if (!el) return;
  el.textContent = message;
  el.classList.toggle('idle-status-error', !!isError);
  el.classList.add('idle-status-flash');
  setTimeout(() => el.classList.remove('idle-status-flash'), 700);
}

async function loadIdleHosts() {
  const idleBody = document.getElementById('idle-body');
  const idleExportBtnEl = document.getElementById('idle-export-btn');
  const idleStatTracked = document.getElementById('idle-stat-tracked');
  const idleStatScans = document.getElementById('idle-stat-scans');
  const idleStatCount = document.getElementById('idle-stat-count');
  const idleStatThreshold = document.getElementById('idle-stat-threshold');

  if (!idleBody) return;

  setIdleStatus('Consultando histórico de leituras...');

  const params = buildIdleQueryParams();
  const res = await fetch(`/api/idle-hosts?${params.toString()}`);
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.error || `HTTP ${res.status}`);
  }

  const data = await res.json();
  lastIdlePayload = data;

  if (idleStatTracked) idleStatTracked.textContent = String(data.totalTracked || 0);
  if (idleStatScans) idleStatScans.textContent = String(data.scanCount || 0);
  if (idleStatCount) idleStatCount.textContent = String(data.idleCount || 0);
  if (idleStatThreshold) idleStatThreshold.textContent = data.thresholdLabel || '—';

  const hosts = Array.isArray(data.hosts) ? data.hosts : [];
  if (idleExportBtnEl) idleExportBtnEl.disabled = hosts.length === 0;

  if (hosts.length === 0) {
    const emptyMsg = data.message || `Nenhum IP ocioso para o limiar ${data.thresholdLabel || '—'}.`;

    idleBody.innerHTML = `
      <tr class="empty-row">
        <td colspan="8">${escapeHtml(emptyMsg)}</td>
      </tr>`;
    setIdleStatus(emptyMsg);
    logToConsole(`[i] Inatividade: ${emptyMsg}`, 'system-msg');
    return;
  }

  idleBody.innerHTML = '';
  for (const host of hosts) {
    const sinceLabel = host.inactiveSinceIso || host.inactiveSince
      ? formatLocalDateTime(host.inactiveSinceIso || host.inactiveSince)
      : (host.lastSeenIso || host.lastSeen ? formatLocalDateTime(host.lastSeenIso || host.lastSeen) : '—');
    const wasActive = host.neverActive ? 'Não (sempre inativo)' : `Sim (${host.timesSeenActive || 0}×)`;
    const row = document.createElement('tr');
    row.innerHTML = `
      <td>${escapeHtml(host.ip)}</td>
      <td>${escapeHtml(host.hostname || 'N/A')}</td>
      <td>${escapeHtml(sinceLabel)}</td>
      <td><span class="text-danger">${escapeHtml(host.idleFor || '—')}</span></td>
      <td>${escapeHtml(formatLocalDateTime(host.lastCheckedIso || host.lastChecked))}</td>
      <td>${escapeHtml(host.deviceType || 'N/A')}</td>
      <td>${escapeHtml(host.subnet || 'N/A')}</td>
      <td>${escapeHtml(wasActive)}</td>
    `;
    idleBody.appendChild(row);
  }

  const status = data.message
    || `Ociosos: ${data.idleCount} (≥ ${data.thresholdLabel}) · Leituras: ${data.scanCount}` +
      (data.remainedIdle != null ? ` · Continuam: ${data.remainedIdle}` : '') +
      (data.newlyIdle != null ? ` · Novos: ${data.newlyIdle}` : '') +
      (data.recoveredActive != null ? ` · Voltaram ativo: ${data.recoveredActive}` : '');
  setIdleStatus(status);
  logToConsole(`[+] ${status}`, 'success-msg');

  const panel = document.querySelector('.idle-panel');
  if (panel) panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

function exportIdleJson() {
  if (!lastIdlePayload || !Array.isArray(lastIdlePayload.hosts) || lastIdlePayload.hosts.length === 0) {
    alert('Nenhum resultado de ociosos para exportar. Clique em Analisar primeiro.');
    return;
  }

  const blob = new Blob([JSON.stringify(lastIdlePayload, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  const stamp = new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-');
  a.href = url;
  a.download = `ips_ociosos_${stamp}.json`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

function wireIdleControls() {
  const idleRefreshBtn = document.getElementById('idle-refresh-btn');
  const idleExportBtn = document.getElementById('idle-export-btn');

  if (idleRefreshBtn && !idleRefreshBtn.dataset.wired) {
    idleRefreshBtn.dataset.wired = '1';
    idleRefreshBtn.addEventListener('click', async () => {
      idleRefreshBtn.disabled = true;
      try {
        await loadIdleHosts();
      } catch (err) {
        setIdleStatus(`Falha: ${err.message}`, true);
        alert(`Falha ao analisar ociosos: ${err.message}`);
        logToConsole(`[!] Falha ao analisar ociosos: ${err.message}`, 'error-msg');
      } finally {
        idleRefreshBtn.disabled = false;
      }
    });
  }

  if (idleExportBtn && !idleExportBtn.dataset.wired) {
    idleExportBtn.dataset.wired = '1';
    idleExportBtn.addEventListener('click', exportIdleJson);
  }
}

wireIdleControls();
window.addEventListener('DOMContentLoaded', wireIdleControls);

