function switchAdTab(tab) {
  document.querySelectorAll('.ad-tab').forEach((el) => {
    el.classList.toggle('active', el.dataset.adTab === tab);
  });
  const dep = document.getElementById('ad-tab-departed');
  const live = document.getElementById('ad-tab-live');
  if (dep) dep.classList.toggle('hidden', tab !== 'departed');
